    // Call function and store result
    bool res = containsDuplicate(nums);

    // Print result
    if (res)
        cout &lt;&lt; "true" &lt;&lt; endl;
    else
        cout &lt;&lt; "false" &lt;&lt; endl;

    return 0;
}
