// Solution class with method
class Solution {
    // Method to check for duplicates using HashSet
    public boolean containsDuplicate(int[] nums) {
        // Set to store unique elements
        HashSet&lt;Integer&gt; set = new HashSet&lt;&gt;();

        // Add elements to the set
        for (int num : nums) {
            set.add(num);
        }

        // If set size is less, duplicates exist
        return set.size() &lt; nums.length;
    }
}

// Main class to run the solution
public class Main {
    public static void main(String[] args) {
        int[] nums = {1, 2, 3, 1};

        Solution sol = new Solution();

        boolean res = sol.containsDuplicate(nums);

        System.out.println(res ? "true" : "false");
    }
}
